def solve(well_parameters, optimization_constraints):
    # Validate inputs against the contract
    if not isinstance(well_parameters, dict) or not isinstance(optimization_constraints, dict):
        raise ValueError("Both well_parameters and optimization_constraints must be dictionaries.")

    # Check for required keys in well_parameters
    required_well_keys = ['depth', 'angle', 'length']
    for key in required_well_keys:
        if key not in well_parameters:
            raise ValueError(f"Missing required well parameter: {key}")

    # Check for required keys in optimization_constraints
    required_constraint_keys = ['max_depth', 'min_angle', 'max_length']
    for key in required_constraint_keys:
        if key not in optimization_constraints:
            raise ValueError(f"Missing required optimization constraint: {key}")

    # Core logic for optimizing well trajectory
    optimized_trajectory = {
        'optimized_depth': min(well_parameters['depth'], optimization_constraints['max_depth']),
        'optimized_angle': max(well_parameters['angle'], optimization_constraints['min_angle']),
        'optimized_length': min(well_parameters['length'], optimization_constraints['max_length']),
    }

    return optimized_trajectory
